@torch.no_grad()
def generate(vae, n_samples=16, z_dim=20):
    """Sample from the prior and decode."""
    z = torch.randn(n_samples, z_dim)           # z ~ N(0, I)
    x_logits = vae.decode(z)
    return torch.sigmoid(x_logits)              # probability map for each pixel

@torch.no_grad()
def interpolate(vae, x1, x2, steps=10):
    """
    Interpolate in latent space between two images.
    Spherical linear interpolation (slerp) preserves distance from origin.
    """
    mu1, _ = vae.encode(x1)
    mu2, _ = vae.encode(x2)
    alphas  = torch.linspace(0, 1, steps)
    interps = []
    for a in alphas:
        z = (1 - a) * mu1 + a * mu2             # linear interp (slerp is more accurate)
        interps.append(torch.sigmoid(vae.decode(z)))
    return torch.stack(interps)
